// Gather data from all three queries
const rechnungen = $('SELECT Offene Rechnungen').all().map(i => i.json);
const anfragen = $('SELECT Neue Anfragen').all().map(i => i.json);
const auftraege = $('SELECT Aktive Auftraege').all().map(i => i.json);

const today = new Date();
const todayStr = today.toISOString().split('T')[0];

// Calculate overdue invoices
const overdueInvoices = rechnungen.filter(r => {
  if (r.created_at && r.zahlungsziel_tage) {
    const created = new Date(r.created_at);
    const due = new Date(created.getTime() + (r.zahlungsziel_tage || 14) * 86400000);
    return due < today;
  }
  return false;
});

const overdueTotal = overdueInvoices.reduce((sum, r) => sum + (parseFloat(r.brutto) || 0), 0);
const openTotal = rechnungen.reduce((sum, r) => sum + (parseFloat(r.brutto) || 0), 0);

// Build summary object
const summary = {
  date: todayStr,
  overdue_count: overdueInvoices.length,
  overdue_total: Math.round(overdueTotal * 100) / 100,
  open_invoices_count: rechnungen.length,
  open_invoices_total: Math.round(openTotal * 100) / 100,
  new_inquiries_count: anfragen.length,
  new_inquiries: anfragen.slice(0, 5).map(a => ({
    kunde: a.kunde_name || 'Unbekannt',
    leistung: a.leistungsart || a.beschreibung || ''
  })),
  active_orders_count: auftraege.length,
  overdue_items: overdueInvoices.slice(0, 5).map(r => ({
    id: r.id,
    kunde: r.kunde_name || 'Unbekannt',
    betrag: r.brutto,
    mahnstufe: r.mahnstufe || 0
  }))
};

return [{ json: summary }];

const summary = $('Build Summary').first().json;
const ollamaResponse = $input.first().json;

// Extract AI text from Ollama response
let aiText = '';
try {
  aiText = ollamaResponse.message ? ollamaResponse.message.content : '';
} catch (e) {
  aiText = '';
}

// Build fallback text if AI failed
if (!aiText || aiText.length < 20) {
  aiText = 'Guten Morgen! Hier ist Ihr Tagesbriefing fuer den ' + summary.date + '.\n\n';
  aiText += 'Offene Rechnungen: ' + summary.open_invoices_count + ' (' + summary.open_invoices_total + ' EUR)\n';
  if (summary.overdue_count > 0) {
    aiText += 'Davon ueberfaellig: ' + summary.overdue_count + ' (' + summary.overdue_total + ' EUR)\n';
  }
  aiText += 'Neue Anfragen: ' + summary.new_inquiries_count + '\n';
  aiText += 'Aktive Auftraege: ' + summary.active_orders_count + '\n';
  if (summary.overdue_count > 0) {
    aiText += '\nEmpfehlung: Ueberfaellige Rechnungen zeitnah mahnen.';
  }
  if (summary.new_inquiries_count > 0) {
    aiText += '\nEmpfehlung: Neue Anfragen heute bearbeiten.';
  }
}

// Build email HTML
const html = `<html>
<head><style>
  body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; margin: 0; padding: 0; }
  .header { background: linear-gradient(135deg, #1a1a2e, #16213e); color: white; padding: 24px 30px; }
  .content { padding: 24px 30px; }
  .kpi-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(140px, 1fr)); gap: 12px; margin: 16px 0; }
  .kpi { background: #f8f9fa; border-radius: 8px; padding: 12px; text-align: center; }
  .kpi-value { font-size: 24px; font-weight: bold; color: #6366f1; }
  .kpi-label { font-size: 12px; color: #666; }
  .alert { background: #fff3cd; border-left: 4px solid #ffc107; padding: 10px 16px; margin: 8px 0; border-radius: 4px; }
  .briefing-text { background: #f0f4ff; padding: 16px; border-radius: 8px; margin: 16px 0; white-space: pre-line; }
  .footer { background: #f5f5f5; padding: 16px 30px; text-align: center; font-size: 12px; color: #888; }
</style></head>
<body>
  <div class="header">
    <h1>Tagesbriefing - ${summary.date}</h1>
    <p>FreyAI Visions - Automatische Zusammenfassung</p>
  </div>
  <div class="content">
    <div class="kpi-grid">
      <div class="kpi"><div class="kpi-value">${summary.open_invoices_count}</div><div class="kpi-label">Offene Rechnungen</div></div>
      <div class="kpi"><div class="kpi-value" style="color: ${summary.overdue_count > 0 ? '#dc3545' : '#22c55e'}">${summary.overdue_count}</div><div class="kpi-label">Ueberfaellig</div></div>
      <div class="kpi"><div class="kpi-value">${summary.new_inquiries_count}</div><div class="kpi-label">Neue Anfragen</div></div>
      <div class="kpi"><div class="kpi-value">${summary.active_orders_count}</div><div class="kpi-label">Aktive Auftraege</div></div>
      <div class="kpi"><div class="kpi-value">${summary.open_invoices_total.toFixed(0)} EUR</div><div class="kpi-label">Offene Summe</div></div>
      <div class="kpi"><div class="kpi-value" style="color: ${summary.overdue_total > 0 ? '#dc3545' : '#22c55e'}">${summary.overdue_total.toFixed(0)} EUR</div><div class="kpi-label">Ueberfaellig</div></div>
    </div>
    ${summary.overdue_count > 0 ? '<div class="alert">Achtung: ' + summary.overdue_count + ' Rechnung(en) ueberfaellig (' + summary.overdue_total.toFixed(2) + ' EUR)</div>' : ''}
    <div class="briefing-text">${aiText.replace(/\n/g, '<br>')}</div>
  </div>
  <div class="footer">
    <p>Automatisch generiert von FreyAI Visions | ${new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' })}</p>
  </div>
</body>
</html>`;

return [{ json: {
  summary: summary,
  ai_text: aiText,
  email_html: html,
  subject: 'Tagesbriefing ' + summary.date + ' - ' + summary.open_invoices_count + ' offene Rechnungen, ' + summary.new_inquiries_count + ' neue Anfragen'
} }];

